SELECT eval_period_id AS evalPeriodId, eval_year AS evalYear, eval_sequence AS evalSequence, eval_type AS evalType, start_date AS startDate, end_date AS endDate, status, algorithm_version_id AS algorithmVersionId FROM evaluation_period
AND eval_year = #{year} AND status = #{status}
ORDER BY eval_year DESC, eval_sequence DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM evaluation_period

    AND eval_year = #{year}
    AND status = #{status}

SELECT qe.qualitative_evaluation_id AS evalId, qe.evaluatee_id AS evaluateeId, e.employee_name AS employeeName, e.employee_tier AS employeeTier, qe.evaluation_period_id AS evaluationPeriodId, qe.evaluation_level AS evaluationLevel, qe.grade, qe.score, qe.status FROM qualitative_evaluation qe JOIN employee e ON e.employee_id = qe.evaluatee_id
qe.evaluation_period_id = #{periodId} AND qe.grade = #{grade} AND qe.status = #{status}
ORDER BY qe.evaluation_level, e.employee_name LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM qualitative_evaluation qe

    qe.evaluation_period_id = #{periodId}
    AND qe.grade = #{grade}
    AND qe.status = #{status}
